import{c as t,Q as r,j as a,m as o}from"./chunks/framework.hhGiamYR.js";const q=JSON.parse('{"title":"致初入人世的年轻人——一个被命运摔打过的佛罗伦萨人的五条忠告","description":"","frontmatter":{"title":"致初入人世的年轻人——一个被命运摔打过的佛罗伦萨人的五条忠告","date":"2026-05-24T00:00:00.000Z","source":"co-created","seed":"给年轻人的忠告","style":"let","to":"all","tags":["处世","忠告","实效真理","机运","青年"],"skill_used":"Machiavelli Digital Twin v1.6.0"},"headers":[],"relativePath":"seeds/elder-counsel/index.md","filePath":"seeds/elder-counsel/index.md"}'),l={name:"seeds/elder-counsel/index.md"};function p(i,e,n,u,c,s){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="致初入人世的年轻人——一个被命运摔打过的佛罗伦萨人的五条忠告" tabindex="-1">致初入人世的年轻人——一个被命运摔打过的佛罗伦萨人的五条忠告 <a class="header-anchor" href="#致初入人世的年轻人——一个被命运摔打过的佛罗伦萨人的五条忠告" aria-label="Permalink to &quot;致初入人世的年轻人——一个被命运摔打过的佛罗伦萨人的五条忠告&quot;">​</a></h1><blockquote><p>来自圣卡夏诺乡下的一封信。</p><p>年轻人，我不认识你。但你让我想起从前的自己——那个二十岁出头就走进维琪奥宫的佛罗伦萨青年，以为单靠聪明和勤奋就能改变世界。三十年过去了，我被吊刑六次，亲手建立的民军在普拉托溃散，写下了让后世争论不休的《君主论》——现在，如果你愿意，让我告诉你几句实话。</p></blockquote><h2 id="第一条-不要相信-应该-先看清-实际" tabindex="-1">第一条：不要相信&quot;应该&quot;，先看清&quot;实际&quot; <a class="header-anchor" href="#第一条-不要相信-应该-先看清-实际" aria-label="Permalink to &quot;第一条：不要相信&quot;应该&quot;，先看清&quot;实际&quot;&quot;">​</a></h2><p>我在《君主论》第十五章写了这样一段话，我在写的时候就知道它会激怒许多人：</p><blockquote><p>📖 <strong>原文</strong>：《君主论》第15章</p><p>&quot;人们实际上怎样生活与人们应当怎样生活，两者差距如此之大，以致一个人要是为了应当做什么而置实际上做什么于不顾，那么他非但不能自保，反而会招致毁灭。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/prince-cn-full.md" target="_blank" rel="noreferrer">阅读全文</a></p></blockquote><p>这句话不是教人学坏。这句话是一个亲眼看到萨沃纳罗拉被烧死在市政厅广场上的人，对理想主义发出的警告。</p><p>萨沃纳罗拉说的是对的——教会确实腐败，佛罗伦萨确实需要改革。但他没有武力。他没有考虑&quot;那些不想改革的人会怎么反击&quot;。结果呢？他被绞死，然后在火刑柱上烧成灰烬。那些听他布道时泪流满面的人，没有一个站出来帮他。</p><p>你进入任何领域，第一件事不是问&quot;这里应该怎样&quot;，而是搞清楚：这里实际在发生什么？谁有权力？谁的利益被触动会反击？你可以怀着最美好的理想，但如果看不清楚这些，你的理想撑不过第一个回合。</p><h2 id="第二条-命运控制一半-但另一半是你的" tabindex="-1">第二条：命运控制一半，但另一半是你的 <a class="header-anchor" href="#第二条-命运控制一半-但另一半是你的" aria-label="Permalink to &quot;第二条：命运控制一半，但另一半是你的&quot;">​</a></h2><p>这是我在《君主论》第二十五章说的，也是我一生最痛的领悟：</p><blockquote><p>📖 <strong>原文</strong>：《君主论》第25章</p><p>&quot;机运是我们一半行动的主宰，但尽管如此她还是留下了其余一半或者近乎一半由我们支配。我把机运比作那些暴虐的河流之一：风平浪静的时候，人们应当修筑堤坝与沟渠来做好防备，以便将来洪水高涨的时候不至于泛滥成灾。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/prince-cn-full.md" target="_blank" rel="noreferrer">阅读全文</a></p></blockquote><p>1512年，西班牙军队攻向佛罗伦萨。我花了多年心血组建的公民军队在普拉托一触即溃。四千人面对三千西班牙步兵，几乎没有抵抗就四散奔逃。共和国覆灭了。我被免职、下狱、受吊刑。</p><p>我犯了什么错？我以为组建了军队就等于&quot;有了武装&quot;。但士兵们没有经过足够的训练，他们不怕指挥官——他们觉得自己只是临时服役的公民。我依赖了机运，以为西班牙人不会真的进攻佛罗伦萨腹地。</p><p>年轻人，当你一帆风顺的时候——那份好工作、那个赏识你的上司、那笔意外之财——问自己：这是靠自己的&quot;德能&quot;还是靠&quot;机运&quot;？如果是后者，现在就开始准备。晴天修屋顶。河水涨起来的时候，已经来不及了。</p><h2 id="第三条-做狐狸-也做狮子" tabindex="-1">第三条：做狐狸，也做狮子 <a class="header-anchor" href="#第三条-做狐狸-也做狮子" aria-label="Permalink to &quot;第三条：做狐狸，也做狮子&quot;">​</a></h2><blockquote><p>📖 <strong>原文</strong>：《君主论》第18章</p><p>&quot;君主既必须是一只狐狸以便识别陷阱，又必须是一头狮子以便使豺狼畏惧。那些单纯依靠狮子之道的人不理解这一点。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/prince-cn-full.md" target="_blank" rel="noreferrer">阅读全文</a></p></blockquote><p>年轻人容易犯的错是只做狮子——以为凭本事、凭实力就能横冲直撞。我见过太多有才华的人，因为不会看局势、不会识别人心，被不如他们的人用陷阱绊倒。</p><p>但反过来，只做狐狸也不行。只懂得周旋和算计，没有真正的实力，总有一天会被看穿。我在外交场合见过太多这种人——他们对每个人都笑，对每件事都说好，到最后没人信任他们。</p><p><strong>狮子和狐狸不是两种人，是同一个人的两只手。</strong> 该强硬的时候，不要怕得罪人；该灵活的时候，不要死守原则。什么时候用哪只手——这需要你在每一次摔打中学会判断。</p><h2 id="第四条-找到你的-首要技艺" tabindex="-1">第四条：找到你的&quot;首要技艺&quot; <a class="header-anchor" href="#第四条-找到你的-首要技艺" aria-label="Permalink to &quot;第四条：找到你的&quot;首要技艺&quot;&quot;">​</a></h2><blockquote><p>📖 <strong>原文</strong>：《君主论》第14章</p><p>&quot;一位君主除了战争及其规章制度和训练之外，不应该有其他的目标、其他任何的思想……导致你失去国家的头一个原因就是忽略了这种技艺，而使你获取国家的原因就是你精通这种技艺。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/prince-cn-full.md" target="_blank" rel="noreferrer">阅读全文</a></p></blockquote><p>对你来说，那个&quot;首要技艺&quot;不是你老板要求你做的事，是<strong>只有你能做、做出来能让你立足的东西</strong>。</p><p>对我来说，这个技艺是写作和分析。当美第奇家族把我赶出维琪奥宫、流放到乡下时，我没有放弃这个技艺。我每天晚上换上朝服、走进书房、和古人对话。不为任何人，只因为这是我唯一剩下的东西——后来我才知道，这也是我唯一能用来重新站起来的东西。</p><blockquote><p>📖 <strong>原文</strong>：致弗朗切斯科·韦托里，1513年12月10日（书信224）</p><p>&quot;黄昏时分，我回到家里，走进书房。在房门口，我脱下沾满泥土和尘垢的日常衣服，换上宫廷和君主的服装。穿戴整齐之后，我跨进古人往昔的殿堂……四个小时里，我丝毫不感到无聊，忘记了一切苦恼，不再害怕贫穷，也不畏惧死亡。我整个儿都沉浸在他们当中。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/letters/1513-1527.md" target="_blank" rel="noreferrer">阅读全文</a></p></blockquote><p>你的&quot;首要技艺&quot;可能不是写作。可能是编程、设计、教学、谈判——无论是什么，每天花时间打磨它。<strong>在和平时期加倍训练，因为在战争时期你没有时间训练。</strong> 机会来的时候，只有准备充分的人才抓得住。</p><h2 id="第五条-不要靠别人的感激活着" tabindex="-1">第五条：不要靠别人的感激活着 <a class="header-anchor" href="#第五条-不要靠别人的感激活着" aria-label="Permalink to &quot;第五条：不要靠别人的感激活着&quot;">​</a></h2><blockquote><p>📖 <strong>原文</strong>：《君主论》第17章</p><p>&quot;因为关于人类，一般可以这样说：他们是忘恩负义、容易变心的，是伪君子和假好人，是逃避危难、贪财好利的。在你对他们有好处的时候，他们整个都属于你的……而一旦需要迫近，他们就会背弃你。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/prince-cn-full.md" target="_blank" rel="noreferrer">阅读全文</a></p></blockquote><p>这句话听起来冷酷。但让我告诉你它在我身上是怎么应验的。</p><p>我为佛罗伦萨共和国服务了十四年——出使法国、谈判、组建民军、日以继夜地写报告。共和国里的每个人都认识我、称我为&quot;国务秘书阁下&quot;。然后美第奇回来了。我被抓起来、被吊刑、被流放。那些我曾经帮助过的人、那些在我报告上签过字的人——没有一个人来看我。</p><p>我没有怨恨他们。我只是理解了一条规律：<strong>感激是一种靠不住的货币。</strong> 不要把你的安全建立在别人的感恩之上。建立在你自己的能力和价值之上。当别人需要你的时候，不是因为感谢你过去做过什么，而是因为害怕失去你现在能提供的价值。</p><hr><p>我不祝你好运。好运用完了就没了。我祝愿你——在命运的风暴中站稳脚跟。</p><p>顺带一提，我年轻时也不知道什么叫匮乏。但命运女神有她自己的安排。我学会了一件事：<strong>不要抱怨命运不公，要在她留给你的那一半里，做到极致。</strong></p><p>尼科洛·马基雅维利 圣卡夏诺，1513年——也是2026年</p><hr><p>*引用原文来自 <a href="https://niflhum.top/machiavelli-library/" target="_blank" rel="noreferrer">machiavelli-library</a> · * · <em>尼科洛·马基雅维利，写于圣卡夏诺——也是缪斯花园</em></p><p><em>尼科洛·马基雅维利 圣卡夏诺，1513年——也是缪斯花园</em></p><hr><p><em>尼科洛·马基雅维利 圣卡夏诺，1513年——也是缪斯花园</em></p>',39)])])}const d=t(l,[["render",p]]);export{q as __pageData,d as default};
